changeSet.createView:
SELECT /* ── Identification du crédit ────────────────────────────── */ c.IDCREDIT, c.NUMCREDIT, c.STATUT AS statut_credit, c.OBJET_CREDIT, c.CODE_OBJET_CREDIT, c.NUMEROCYCLE, c.PERIODICITE, c.DUREE, c.NOMBRE_ECHEANCE,
/* ── Membre emprunteur ───────────────────────────────────── */ m.NUM_MEMBRE, m.NOM AS nom_membre, m.PRENOM AS prenom_membre, m.SEXE,
/* ── Agence ──────────────────────────────────────────────── */ ag.CODE_AGENCE, ag.NOMAGENCE AS nom_agence,
/* ── Agent crédit ────────────────────────────────────────── */ ac.CODE_AGENT, ac.DESIGNATION AS nom_agent,
/* ── Paramètres financiers ───────────────────────────────── */ c.TAUX_INTERET, c.TAUX_PENALITE, c.TAUX_COMMISSION, c.TAUX_ASSURANCE,
/* ── Dates clés ──────────────────────────────────────────── */ c.DATE_DEMANDE, c.DATE_ACCORD, c.DATE_DEBLOCAGE, c.DATE_PREMIERE_ECHEANCE, c.DATE_ECHEANCE AS date_echeance_finale, c.DATE_CLOTURE,
/* ── Montants ────────────────────────────────────────────── */ c.MONTANT_DEMANDE, c.MONTANT_ACCORDE, c.MONTANT_DEBLOQUER AS montant_debloque, c.SOLDE_CAPITAL, c.SOLDE_INTERET, c.SOLDE_PENALITE, c.SOLDE_CAPITAL + c.SOLDE_INTERET + c.SOLDE_PENALITE AS solde_total_du,
/* ── PAR (Portefeuille à Risque) — NULL si non DEBLOQUE ─── */ COALESCE(par.max_jours_retard, 0) AS jours_retard, COALESCE(par.nb_echeances_retard, 0) AS nb_echeances_retard, COALESCE(par.total_arrieres, 0) AS total_arrieres, COALESCE(par.capital_retard, 0) AS capital_retard, COALESCE(par.interet_retard, 0) AS interet_retard, COALESCE(par.penalite_retard, 0) AS penalite_retard, par.date_premiere_echeance_retard, COALESCE(par.categorie_par, 'SAIN') AS categorie_par,
/* ── Couverture par garanties ────────────────────────────── */ COALESCE(gar.total_garanties, 0) AS total_garanties, CASE WHEN c.MONTANT_DEBLOQUER > 0 THEN CAST(COALESCE(gar.total_garanties, 0) AS FLOAT) / CAST(c.MONTANT_DEBLOQUER AS FLOAT) * 100 ELSE 0 END AS taux_couverture_pct
FROM Credits c
LEFT JOIN membres m ON m.NUM_MEMBRE = c.nummembre
LEFT JOIN AGENCE ag ON ag.CODE_AGENCE = c.agence
LEFT JOIN AGENT_CREDIT ac ON ac.CODE_AGENT = c.agentcredit
/* PAR uniquement pour les crédits DEBLOQUE */ LEFT JOIN vue_par_bcm par ON par.IDCREDIT = c.IDCREDIT
/* Somme des garanties actives toutes sources confondues */ LEFT JOIN ( SELECT g.idcredit, SUM(g.valeur_estimee) AS total_garanties FROM vue_garanties_unifiee g GROUP BY g.idcredit ) gar ON gar.idcredit = c.IDCREDIT
